INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00130', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於 X3 年初以$2,000,000 承包為期 3 年之工程合約，經評估該合約係隨時間逐步滿足 之單一履約義務，且以已發生成本占總成本比例為基礎之投入法衡量該合約之完成程度係屬 適當。甲公司 X3 年為該合約發生之成本為$500,000，且 X3 年底估計未來尚須投入成本 $500,000始能完成該合約。甲公司X4年為該合約投入之成本為$1,500,000，且X4年底估計 未來尚須投入成本$500,000 始能完成該合約。若甲公司亦得於 X4 年底選擇支付罰款 $1,000,000 以終止該合約，則甲公司 X4 年為該合約應認列計入本期淨利之費損總金額是多 少？', '["$1,000,000", "$1,500,000", "$1,600,000", "$2,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00131', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司 X3 年度會計稅前淨利為$780,000，除下列項目外並無其他影響會計稅前淨利與課稅 所得差異之事項：⑴X3 年底資產負債表上產品保證負債較上一年度減少$36,000；⑵一機器 設備 X3 年初帳面金額為$180,000，課稅基礎為$150,000；X3 年底機器設備帳面金額為 $135,000，課稅基礎為$90,000。若各年度稅率均為20%，則甲公司X3年底有關所得稅分錄 中應認列之應付所得稅為何？', '["$145,800", "$151,800", "$160,200", "$166,200"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00132', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司X3年初按公允價值$602,864出售一部機器給乙公司，該機器原始成本為$1,000,000，累 計折舊$500,000，剩餘耐用年限5年。甲公司立即簽約租回，租期3年，每年1月1日給付租 金$140,000，租期屆滿機器歸還乙公司，期滿估計殘值為$100,000，且全數由甲公司保證，但甲 公司預期租期屆滿時機器之價值僅$40,000。已知甲公司之增額借款利率為6%，乙公司之隱含 利率為 5%，且為甲公司所知。若甲公司對該設備之移轉符合銷售之規定，則甲公司 X3 年應 認列處分機器損益為何？（p =0.86384；p =0.83962；P =2.72325；P =2.67301） 3,5% 3,6% 3,5% 3,6%', '["利益$25,716", "利益$26,586", "利益$28,664", "利益$29,451"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00133', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', 'X1 年初甲公司發行面額$10、5%之可轉換累積特別股 10,000 股，每股特別股可轉換成 2 股 普通股，X1年甲公司未宣告發放現金股利。X2年4月1日甲公司發行100張面額$10,000之 可轉換公司債，票面利率4%，每年底付息一次，每張公司債可轉換成普通股1,000股，可轉 換公司債發行時負債組成部分為$1,000,000，有效利率亦為4%，權益組成部分為$60,000，至 X2年底該公司債並未轉換。X2年6月30日公司宣告並發放特別股股利，X2年10月1日面 額$60,000之可轉換特別股轉換為普通股。X2年初甲公司有普通股200,000股流通在外，X2 年度稅後淨利$370,400，所得稅率20%，則X2年度稀釋每股盈餘是多少？（四捨五入取至小 數點下三位）', '["$1.323", "$1.337", "$1.540", "$1.800"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00134', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X3年1月1日以$1,027,751購入面額$1,000,000三年期的公司債，票面利率5%， 有效利率4%，每年年底付息，甲公司將該債券投資分類為透過其他綜合損益按公允價值衡量 之債券投資。X3年12月31日市場利率降為3%，該公司債公允價值上升為$1,038,269，甲公 司於X3年12月31日決定改變其管理債券之經營模式，並將該債券投資重分類為透過損益 按公允價值衡量。甲公司X3年底判斷自公司債原始認列後信用風險並未顯著增加，估計12 個月預期信用損失為$8,000，存續期間預期信用損失為$20,000。試問甲公司應認列之重分類 損益為何？（四捨五入取整數）', '["無重分類損益", "重分類損失$592", "重分類利益$19,408", "重分類利益$27,408"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00135', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '丙公司於X1年1月1日發行2年期的公司債，並將其指定為透過損益按公允價值衡量之金 融負債，面額$10,000，票面利率 10%，每年 12 月 31 日付息一次，發行公司債取得的價金 $10,000。於原始認列時，丙公司認定將該公司債信用風險變動影響數認列於其他綜合損益， 並不會引發或加劇會計配比不當。該公司債之原始有效利率為10%，此時市場基準利率為8%。 X1年12月31日，該公司債期末公允價值為$10,000。此時市場基準利率為5%。若採IFRS9 預設之方法，丙公司X1年12月31日有關該公司債當期之公允價值變動金額中，應認列於 本期其他綜合損益之金額為何？（計算至整數，以下四捨五入，不考慮所得稅之影響）', '["$0", "其他綜合利益$280", "其他綜合損失$280", "其他綜合利益$720"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "75afc66abdb3", "answer_pdf_sha1": "056779a0b842", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00136', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'essay', '甲旅行社租用乙交通公司之遊覽車出團花蓮太魯閣 2 日遊，由靠行乙營
業之丙駕駛，該遊覽車身並有「乙交通公司」字樣，途中不慎發生車禍
翻車，造成該旅行團員丁身體受傷。問丁得向甲、乙及丙請求何種權利？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00137', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'essay', '甲原住民向乙原住民承租 A原住民保留地做造林之用，雙方訂立租賃契
約，約定得在 A地採伐杉木。甲除植木於 A地外，亦過失越界在同屬乙
之 B原住民保留地植木。甲在開始採伐林木前，B地被乙售與非原住民
丙，借名登記於原住民丁，並已辦理所有權移轉登記。甲開採後取得在
B 地所種之杉木，價值 10 萬元。問丙得否對甲主張該杉木之所有權？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00138', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '附條件之買賣契約當事人，於條件成否未定前，損害相對人因條件成就所應得利益之行為者，有 何法律上之效力？', '["條件成就時，始負賠償損害之責任", "損害發生時，條件尚未成就，法律行為失效", "立即負有賠償損害之責任", "相對人得解除契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00139', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何種契約，屬於若無書面即屬無效之契約？', '["人事保證", "和解", "合夥", "物品運送"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
